solutions.javascript:
var angleClock = function(hour, minutes) {
    const minuteAngle = minutes * 6.0;
    const hourAngle = (hour % 12) * 30.0 + minutes * 0.5;
    const diff = Math.abs(minuteAngle - hourAngle);
    return Math.min(diff, 360.0 - diff);
};
